const items = $input.all();
const now = new Date();
now.setHours(0,0,0,0);

const actions = [];

for (const item of items) {
  const row = item.json;
  if (!row.Client_Email) continue;

  const status = (row.Status || '').toLowerCase();
  if (['completed', 'cancelled', 'on-hold'].includes(status)) continue;

  const base = {
    client_name: row.Client_Name || 'Client',
    client_email: row.Client_Email,
    project_name: row.Project_Name || 'Your Project',
    status: row.Status || 'In Progress',
    progress_pct: row.Progress_Pct || '0',
    deadline: row.Deadline || '',
    last_update_sent: row.Last_Update_Sent || '',
    invoice_amount: row.Invoice_Amount || '',
    invoice_due_date: row.Invoice_Due_Date || '',
    invoice_status: (row.Invoice_Status || 'pending').toLowerCase(),
    invoice_reminder_count: parseInt(row.Invoice_Reminder_Count || '0'),
    notes: row.Notes || ''
  };

  // Project update: send every 48h for active projects
  let shouldSendUpdate = false;
  if (base.last_update_sent) {
    const lastSent = new Date(base.last_update_sent);
    const hoursSinceUpdate = (now - lastSent) / (1000 * 60 * 60);
    if (hoursSinceUpdate >= 48) shouldSendUpdate = true;
  } else {
    shouldSendUpdate = true; // never sent
  }

  if (shouldSendUpdate && status === 'in progress') {
    actions.push({ json: { ...base, _action: 'project_update' } });
  }

  // Invoice overdue check
  if (base.invoice_amount && base.invoice_due_date && base.invoice_status === 'unpaid') {
    let dueDate;
    try {
      dueDate = new Date(base.invoice_due_date);
      dueDate.setHours(0,0,0,0);
    } catch { dueDate = null; }

    if (dueDate) {
      const daysOverdue = Math.round((now - dueDate) / (1000 * 60 * 60 * 24));
      if (daysOverdue >= 1 && base.invoice_reminder_count < 3) {
        actions.push({ json: { ...base, _action: 'invoice_reminder', days_overdue: daysOverdue } });
      }
    }
  }
}

console.log(`Freelancer actions: ${actions.length}`);
return actions.length > 0 ? actions : [{ json: { _action: 'none' } }];

// Increment invoice reminder count
const item = $input.first().json;
return [{ json: { ...item, new_reminder_count: item.invoice_reminder_count + 1 } }];
